import React from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function AdminLayout({ children }) {
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const handleLogout = async () => {
    await logout();
    navigate("/");
  };

  const navItems = [
    { to: "/admin", label: "Dashboard", icon: "📊" },
    { to: "/admin/events", label: "Events", icon: "📅" },
    { to: "/admin/users", label: "Users", icon: "👥" },
    { to: "/admin/categories", label: "Categories", icon: "🏷️" },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#191919" }}>
      {/* Sidebar */}
      <aside
        style={{
          width: "280px",
          background: "#0a0a0a",
          borderRight: "1px solid #2a2a2a",
          padding: "24px 16px",
          position: "fixed",
          height: "100vh",
          overflowY: "auto",
        }}
      >
        <div style={{ marginBottom: "32px" }}>
          <Link
            to="/"
            style={{
              textDecoration: "none",
              color: "#fff",
              fontSize: "18px",
              fontWeight: 800,
              letterSpacing: "0.02em",
            }}
          >
            Hometown<span style={{ color: "#ff00e0" }}>Post</span>
          </Link>
          <p style={{ color: "#666", fontSize: "12px", marginTop: "4px" }}>Admin Portal</p>
        </div>

        <nav style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
          {navItems.map(({ to, label, icon }) => (
            <Link
              key={to}
              to={to}
              style={{
                display: "flex",
                alignItems: "center",
                gap: "12px",
                padding: "10px 14px",
                borderRadius: "6px",
                textDecoration: "none",
                fontSize: "14px",
                fontWeight: 500,
                color: isActive(to) ? "#ff00e0" : "#999",
                background: isActive(to) ? "rgba(255,0,224,0.1)" : "transparent",
                borderLeft: isActive(to) ? "3px solid #ff00e0" : "3px solid transparent",
                transition: "all 0.2s",
              }}
              onMouseEnter={(e) => {
                if (!isActive(to)) {
                  e.currentTarget.style.color = "#ff00e0";
                  e.currentTarget.style.background = "rgba(255,0,224,0.05)";
                }
              }}
              onMouseLeave={(e) => {
                if (!isActive(to)) {
                  e.currentTarget.style.color = "#999";
                  e.currentTarget.style.background = "transparent";
                }
              }}
            >
              <span style={{ fontSize: "18px" }}>{icon}</span>
              {label}
            </Link>
          ))}
        </nav>

        <div style={{ marginTop: "32px", borderTop: "1px solid #2a2a2a", paddingTop: "16px" }}>
          <Link
            to="/"
            style={{
              display: "block",
              padding: "10px 14px",
              borderRadius: "6px",
              textDecoration: "none",
              fontSize: "13px",
              fontWeight: 500,
              color: "#666",
              transition: "all 0.2s",
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.color = "#999";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.color = "#666";
            }}
          >
            ← Back to Site
          </Link>
        </div>
      </aside>

      {/* Main Content */}
      <main style={{ marginLeft: "280px", flex: 1 }}>
        {children}
      </main>
    </div>
  );
}
